const PROCESSING_FEE = 5;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

export const runScenario = (scenario: Scenario): unknown => {
  const results = scenario.steps.map((step) => {
    const policyBase = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
    const firstInsurance = policyBase * 0.1;
    return { premium: policyBase + firstInsurance + PROCESSING_FEE };
  });
  return { results };
};

