const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const BLOCK_OF_THREE_PREMIUM = 60;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const isCompleteBlock = (type: string, count: number): boolean =>
  COMPONENT_TYPES.has(type) && count === 3;

const premiumForTypeCount = (type: string, count: number): number =>
  isCompleteBlock(type, count)
    ? BLOCK_OF_THREE_PREMIUM
    : count * BASE_PREMIUMS[type];

const basePremiumOf = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    total += premiumForTypeCount(type, count);
  }
  return total;
};

const quoteForStep = ({ items }: QuoteStep) => {
  const basePremium = basePremiumOf(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  return { premium: basePremium + firstInsuranceSurcharge + PROCESSING_FEE };
};

export const runScenario = (scenario: Scenario): unknown => {
  return { results: scenario.steps.map(quoteForStep) };
};

