import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Trivial / empty cases ---
  it("empty item list quote -> premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // --- Base premiums for main items (with implicit first-insurance and fee) ---
  // For a brand-new customer (0 years, no prior contract): premium = base + 10% first-insurance + 5 G fee
  it("single sword for new customer -> 100 base + 10 first + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet for new customer -> 60 base + 6 first + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff for new customer -> 80 base + 8 first + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff", material: "wood", enchantment: 2, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion for new customer -> 40 base + 4 first + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // --- Component pricing & block-of-3 rule ---
  it("2 runes for new customer -> 50 base + 5 first + 5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes for new customer -> 60 base + 6 first + 5 fee = 71 G (block applies)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes for new customer -> 100 base + 10 first + 5 fee = 115 G (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" },
      ] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes for new customer -> 175 base + 17.5 first + 5 fee = 197.5 -> rounded UP 198 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: Array.from({ length: 7 }, () => ({ type: "rune" })) }],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("2 runes + 1 moonstone for new customer -> 75 base + 7.5 first + 5 fee = 87.5 -> 88 G (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones for new customer -> 120 base + 12 first + 5 fee = 137 G (two blocks)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
      ] }],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // --- Modifier scope on multi-item policies ---
  it("cursed sword + plain amulet (new customer) -> 100+60 base + 50 curse + 10+6 first + 5 fee = 231 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "sword", material: "steel", enchantment: 3, cursed: true },
        { type: "amulet", material: "silver", enchantment: 2, cursed: false },
      ] }],
    });
    expect(result).toEqual({ results: [{ premium: 231 }] });
  });

  // --- Modifier thresholds ---
  it("customer with exactly 2 years, single sword -> 100 + 10 first - 20 loyalty + 5 fee = 95 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 95 }] });
  });
  it("sword with exactly enchantment 5 (new customer) -> 100 + 30 high-ench + 10 first + 5 fee = 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it.todo("cursed sword with enchantment 5 -> both curse and high-enchantment surcharges apply");
  it.todo("sword with enchantment 4 (not cursed) -> no surcharges");

  // --- Rounding ---
  it.todo("premium yielding 197.5 G -> rounded UP to 198 G (in MHPCO's favor)");
  it.todo("payout yielding 350.5 G -> rounded DOWN to 350 G (in MHPCO's favor)");

  // --- Integration examples ---
  it.todo("newcomer with cursed sword (steel, ench 3) -> premium 165 G");
  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3 years -> 160 G");

  // --- Claim: standard reimbursement ---
  it.todo("regular sword (steel, ench 3), damage 500 G -> payout 400 G (500 - 100 deductible)");
  it.todo("damage to a rune (value 250), damage 200 -> payout 100 G (200 - 100)");

  // --- Claim: enchantment & dragon material clauses ---
  it.todo("dragon-material sword, ench 8, damage 1000 -> payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 -> payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, ench 5, damage 800 -> payout 700 G (dragon full, then deductible)");
  it.todo("steel sword, ench 9, damage 1000 -> payout 400 G (50% then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) -> payout 600 G (100 deductible per item)");

  // --- Claim: cap ---
  it.todo("policy covers sword + amulet -> insurance sum 1600, cap 3200 G");
  it.todo("cursed sword -> cap 2000 G (based on unmodified insurance value)");
  it.todo("policy covers sword + 3 runes (block) -> insurance sum 1750 G");
  it.todo("sword cap 2000, claim 1500 -> payout 1400, remaining cap 600");
  it.todo("second claim of 1500 -> payout 600 (capped), remaining cap 0");

  // --- Multiple items of the same type ---
  it.todo("policy covers two swords -> insurance sum 2000 G, cap 4000 G");
  it.todo("two swords, two damage entries -> each gets its own deductible");
  it.todo("damages has more entries of a type than policy covers -> CLI exits non-zero");

  // --- Error cases ---
  it.todo("quote with unknown item type -> CLI exits non-zero, error on stderr, no results");
  it.todo("claim references item not in policy -> CLI exits non-zero, error on stderr");
  it.todo("claim damage with negative amount -> CLI exits non-zero, error on stderr");
});

